import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{r as e,o,c as p,a as n,b as c,d as i,e as s}from"./app-58480cea.js";const l="/assets/image-20200719084018801-20230617195252-t6ezdk7-d1d652a6.png",u={},d=s('<h1 id="数据类型" tabindex="-1"><a class="header-anchor" href="#数据类型" aria-hidden="true">#</a> 数据类型</h1><p>Go 语言中数据类型分为：基本数据类型和复合数据类型</p><ul><li><p>基本数据类型有：整型、浮点型、布尔型、字符串</p></li><li><p>复合数据类型有：数组、切片、结构体、函数、map、通道（channel）、接口等。</p></li></ul><h2 id="数字" tabindex="-1"><a class="header-anchor" href="#数字" aria-hidden="true">#</a> 数字</h2><blockquote><p>在 Go 语言中，<code>int</code>​ 和 <code>float</code>​ 的大小依赖于底层计算机的体系结构和操作系统。在大多数平台上，<code>int</code>​ 类型的大小是 32 位或 64 位，而 <code>float</code>​ 类型的大小通常是 32 位或 64 位。</p><p>具体来说，<code>int</code>​ 类型在 32 位系统上是 32 位的有符号整数，范围为 <code>-2,147,483,648</code>​ 到 <code>2,147,483,647</code>​，而在 64 位系统上是 64 位的有符号整数，范围为 <code>-9,223,372,036,854,775,808</code>​ 到 <code>9,223,372,036,854,775,807</code>​。<code>float</code>​ 类型在 32 位系统上是 32 位的浮点数，而在 64 位系统上是 64 位的浮点数。</p><p>需要注意的是，在不同平台和编译器下，<code>int</code>​ 和 <code>float</code>​ 的大小可能会有所不同，因此在编写程序时需要谨慎考虑跨平台的兼容性问题。为了确保代码的可移植性，建议使用明确的整数和浮点类型，如 <code>int32</code>​、<code>int64</code>​、<code>float32</code>​ 和 <code>float64</code>​。</p></blockquote><h3 id="整型" tabindex="-1"><a class="header-anchor" href="#整型" aria-hidden="true">#</a> 整型</h3><p>整型的类型有很多中，包括 int8，int16，int32，int64。我们可以根据具体的情况来进行定义</p><p>​<img src="'+l+`" alt="image-20200719084018801" loading="lazy">​</p><blockquote><p>可以通过unsafe.Sizeof 查看不同长度的整型，在内存里面的存储空间</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>var num2 = 12
fmt.Println(unsafe.Sizeof(num2))
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><h4 id="数字字面量语法" tabindex="-1"><a class="header-anchor" href="#数字字面量语法" aria-hidden="true">#</a> 数字字面量语法</h4><p>Go1.13版本之后，引入了数字字面量语法，这样便于开发者以二进制、八进制或十六进制浮点数的格式定义数字，例如：</p><div class="language-go line-numbers-mode" data-ext="go"><pre class="language-go"><code>v <span class="token operator">:=</span> <span class="token number">0b00101101</span>  <span class="token comment">// 代表二进制的101101</span>
v：<span class="token operator">=</span> Oo377       <span class="token comment">// 代表八进制的377</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="进制转换" tabindex="-1"><a class="header-anchor" href="#进制转换" aria-hidden="true">#</a> 进制转换</h4><div class="language-go line-numbers-mode" data-ext="go"><pre class="language-go"><code><span class="token keyword">var</span> number <span class="token operator">=</span> <span class="token number">17</span>
<span class="token comment">// 原样输出</span>
fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;%v\\n&quot;</span><span class="token punctuation">,</span> number<span class="token punctuation">)</span>
<span class="token comment">// 十进制输出</span>
fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;%d\\n&quot;</span><span class="token punctuation">,</span> number<span class="token punctuation">)</span>
<span class="token comment">// 以八进制输出</span>
fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;%o\\n&quot;</span><span class="token punctuation">,</span> number<span class="token punctuation">)</span>
<span class="token comment">// 以二进制输出</span>
fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;%b\\n&quot;</span><span class="token punctuation">,</span> number<span class="token punctuation">)</span>
<span class="token comment">// 以十六进制输出</span>
fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;%x\\n&quot;</span><span class="token punctuation">,</span> number<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="浮点型" tabindex="-1"><a class="header-anchor" href="#浮点型" aria-hidden="true">#</a> 浮点型</h3><p>Go语言支持两种浮点型数：float32和float64。这两种浮点型数据格式遵循IEEE754标准：</p><p>float32的浮点数的最大范围约为3.4e38，可以使用常量定义：math.MaxFloat32。float64的浮点数的最大范围约为1.8e308，可以使用一个常量定义：math.MaxFloat64</p><p>打印浮点数时，可以使用fmt包配合动词%f，代码如下：</p><div class="language-go line-numbers-mode" data-ext="go"><pre class="language-go"><code><span class="token keyword">var</span> pi <span class="token operator">=</span> math<span class="token punctuation">.</span>Pi
<span class="token comment">// 打印浮点类型，默认小数点6位</span>
fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;%f\\n&quot;</span><span class="token punctuation">,</span> pi<span class="token punctuation">)</span>
<span class="token comment">// 打印浮点类型，打印小数点后2位</span>
fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;%.2f\\n&quot;</span><span class="token punctuation">,</span> pi<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p><strong>精度丢失</strong></p></blockquote><p>几乎所有的编程语言都有精度丢失的问题，这是典型的二进制浮点数精度损失问题，在定长条件下，二进制小数和十进制小数互转可能有精度丢失</p><div class="language-go line-numbers-mode" data-ext="go"><pre class="language-go"><code>d <span class="token operator">:=</span> <span class="token number">1129.6</span>
fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>d<span class="token operator">*</span><span class="token number">100</span><span class="token punctuation">)</span> <span class="token comment">//输出112959.99999999</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>解决方法，使用第三方包来解决精度损失的问题</p>`,23),r={href:"http://github.com/shopspring/decimal",target:"_blank",rel:"noopener noreferrer"},k=s(`<blockquote><p>注意：由于浮点数在计算机内部的存储方式是近似值，因此在比较浮点数时，应该使用一个误差范围来判断它们是否相等，而不能直接使用等于号进行比较。</p></blockquote><h2 id="布尔" tabindex="-1"><a class="header-anchor" href="#布尔" aria-hidden="true">#</a> 布尔</h2><p>定义</p><div class="language-go line-numbers-mode" data-ext="go"><pre class="language-go"><code><span class="token keyword">var</span> fl <span class="token operator">=</span> <span class="token boolean">false</span>
<span class="token keyword">if</span> f1 <span class="token punctuation">{</span>
    fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;true&quot;</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
    fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;false&quot;</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="字符串" tabindex="-1"><a class="header-anchor" href="#字符串" aria-hidden="true">#</a> 字符串</h2><p>在Go语言中，字符串类型表示文本数据。字符串是不可变的，意味着一旦创建，就不能修改其内容。在Go中，字符串类型用<code>string</code>​关键字来声明。</p><h3 id="初始化" tabindex="-1"><a class="header-anchor" href="#初始化" aria-hidden="true">#</a> 初始化</h3><p>Go语言里的字符串的内部实现使用UTF-8编码。字符串的值为双引号（&quot;）中的内容，可以在Go语言的源码中直接添加非ASCll码字符，例如：</p><div class="language-go line-numbers-mode" data-ext="go"><pre class="language-go"><code>s1 <span class="token operator">:=</span> <span class="token string">&quot;hello&quot;</span>
s1 <span class="token operator">:=</span> <span class="token string">&quot;你好&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>如果想要定义多行字符串，可以使用反引号</p><div class="language-go line-numbers-mode" data-ext="go"><pre class="language-go"><code><span class="token keyword">var</span> str <span class="token operator">=</span> <span class="token string">\`第一行
第二行\`</span>
fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>str<span class="token punctuation">)</span>
<span class="token comment">// Output:</span>
<span class="token comment">// 第一行</span>
<span class="token comment">// 第二行</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="字符串操作" tabindex="-1"><a class="header-anchor" href="#字符串操作" aria-hidden="true">#</a> 字符串操作</h3><div class="language-go line-numbers-mode" data-ext="go"><pre class="language-go"><code><span class="token comment">// 可以使用 + 运算符来拼接字符串</span>
s <span class="token operator">:=</span> <span class="token string">&quot;Hello, &quot;</span> <span class="token operator">+</span> <span class="token string">&quot;World!&quot;</span>  

<span class="token comment">// 可以使用切片语法来获取字符串的一部分</span>
fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>s<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">:</span><span class="token number">5</span><span class="token punctuation">]</span><span class="token punctuation">)</span>    <span class="token comment">// 输出：Hello</span>


<span class="token comment">// 可以使用 range 关键字来遍历字符串中的每个字符</span>
<span class="token keyword">for</span> <span class="token boolean">_</span><span class="token punctuation">,</span> c <span class="token operator">:=</span> <span class="token keyword">range</span> s <span class="token punctuation">{</span>
    fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token function">string</span><span class="token punctuation">(</span>c<span class="token punctuation">)</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="内置函数" tabindex="-1"><a class="header-anchor" href="#内置函数" aria-hidden="true">#</a> 内置函数</h3><p>Go语言提供了很多用于处理字符串的内置函数，包括：</p><ul><li>​<code>len()</code>​：返回字符串的长度</li><li>​<code>strconv.Atoi()</code>​：将字符串转换为整数。</li><li>​<code>strconv.ParseFloat()</code>​：将字符串转换为浮点数。</li><li>​<code>strconv.ParseBool()</code>​：将字符串转换为布尔值。</li><li>​<code>strconv.Itoa()</code>​：将整数转换为字符串。</li><li>​<code>strconv.FormatFloat()</code>​：将浮点数转换为字符串。</li><li>​<code>strconv.FormatBool()</code>​：将布尔值转换为字符串。</li><li>​<code>strings.ToLower()</code>​：将字符串转换为小写</li><li>​<code>strings.ToUpper()</code>​：将字符串转换为大写</li><li>​<code>strings.Contains(s, substr string) bool</code>​：判断字符串 <code>s</code>​ 是否包含子串 <code>substr</code>​，返回布尔值。</li><li>​<code>strings.HasPrefix(s, prefix string) bool</code>​：判断字符串 <code>s</code>​ 是否以前缀 <code>prefix</code>​ 开始，返回布尔值。</li><li>​<code>strings.HasSuffix(s, suffix string) bool</code>​：判断字符串 <code>s</code>​ 是否以后缀 <code>suffix</code>​ 结束，返回布尔值。</li><li>​<code>strings.Index(s, substr string) int</code>​：查找字符串 <code>s</code>​ 中子串 <code>substr</code>​ 第一次出现的位置，返回位置索引（如果没有找到，则返回 <code>-1</code>​）。</li><li>​<code>strings.LastIndex(s, substr string) int</code>​：查找字符串 <code>s</code>​ 中子串 <code>substr</code>​ 最后一次出现的位置，返回位置索引（如果没有找到，则返回 <code>-1</code>​）。</li><li>​<code>strings.Count(s, substr string) int</code>​：计算字符串 <code>s</code>​ 中子串 <code>substr</code>​ 出现的次数，返回出现次数。</li><li>​<code>strings.Replace(s, old, new string, n int) string</code>​：将字符串 <code>s</code>​ 中前 <code>n</code>​ 个 <code>old</code>​ 子串替换为 <code>new</code>​，返回新字符串。</li><li>​<code>strings.Split(s, sep string) []string</code>​：将字符串 <code>s</code>​ 按照分隔符 <code>sep</code>​ 分割为多个子串，并将它们存储在一个字符串切片中，返回切片。</li><li>​<code>strings.Join(a []string, sep string) string</code>​：将一个字符串切片 <code>a</code>​ 中的所有元素按照分隔符 <code>sep</code>​ 连接为一个字符串，返回连接后的字符串。</li><li>​<code>strings.Trim(s string, cutset string) string</code>​：去除字符串 <code>s</code>​ 两侧的 <code>cutset</code>​ 中包含的字符，返回新的字符串。</li><li>​<code>strings.TrimSpace(s string) string</code>​：去除字符串 <code>s</code>​ 两侧的空格字符，返回新的字符串。</li><li>​<code>strings.TrimLeft(s string, cutset string) string</code>​：去除字符串 <code>s</code>​ 左侧的 <code>cutset</code>​ 中包含的字符，返回新的字符串。</li><li>​<code>strings.TrimRight(s string, cutset string) string</code>​：去除字符串 <code>s</code>​ 右侧的 <code>cutset</code>​ 中包含的字符，返回新的字符串。</li></ul><h3 id="byte-和-rune类型" tabindex="-1"><a class="header-anchor" href="#byte-和-rune类型" aria-hidden="true">#</a> byte 和 rune类型</h3><p>组成每个字符串的元素叫做 “字符”，可以通过遍历字符串元素获得字符。字符用单引号 &#39;&#39; 包裹起来</p><p>Go语言中的字符有以下两种类型</p><ul><li>uint8类型：或者叫byte型，代表了ACII码的一个字符</li><li>rune类型：代表一个UTF-8字符</li></ul><p>当需要处理中文，日文或者其他复合字符时，则需要用到rune类型，rune类型实际上是一个int32</p><p>Go使用了特殊的rune类型来处理Unicode，让基于Unicode的文本处理更为方便，也可以使用byte型进行默认字符串处理，性能和扩展性都有照顾。</p><p>需要注意的是，在go语言中，一个汉字占用3个字节（utf-8），一个字母占用1个字节</p><div class="language-go line-numbers-mode" data-ext="go"><pre class="language-go"><code><span class="token keyword">package</span> main
<span class="token keyword">import</span> <span class="token string">&quot;fmt&quot;</span>

<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
	<span class="token keyword">var</span> a <span class="token builtin">byte</span> <span class="token operator">=</span> <span class="token char">&#39;a&#39;</span>
	<span class="token comment">// 输出的是ASCII码值，也就是说当我们直接输出byte（字符）的时候，输出的是这个字符对应的码值</span>
	fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>a<span class="token punctuation">)</span>
	<span class="token comment">// 输出的是字符</span>
	fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;%c&quot;</span><span class="token punctuation">,</span> a<span class="token punctuation">)</span>

	<span class="token comment">// for循环打印字符串里面的字符</span>
	<span class="token comment">// 通过len来循环的，相当于打印的是ASCII码</span>
	s <span class="token operator">:=</span> <span class="token string">&quot;你好 golang&quot;</span>
	<span class="token keyword">for</span> i <span class="token operator">:=</span> <span class="token number">0</span><span class="token punctuation">;</span> i <span class="token operator">&lt;</span> <span class="token function">len</span><span class="token punctuation">(</span>s<span class="token punctuation">)</span><span class="token punctuation">;</span> i<span class="token operator">++</span> <span class="token punctuation">{</span>
		fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;%v(%c)\\t&quot;</span><span class="token punctuation">,</span> s<span class="token punctuation">[</span>i<span class="token punctuation">]</span><span class="token punctuation">,</span> s<span class="token punctuation">[</span>i<span class="token punctuation">]</span><span class="token punctuation">)</span>
	<span class="token punctuation">}</span>

	<span class="token comment">// 通过rune打印的是 utf-8字符</span>
	<span class="token keyword">for</span> index<span class="token punctuation">,</span> v <span class="token operator">:=</span> <span class="token keyword">range</span> s <span class="token punctuation">{</span>
		fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>index<span class="token punctuation">,</span> v<span class="token punctuation">)</span>
	<span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="修改字符串" tabindex="-1"><a class="header-anchor" href="#修改字符串" aria-hidden="true">#</a> 修改字符串</h3><p>要修改字符串，需要先将其转换成[]rune 或 []byte类型，完成后在转换成string，无论哪种转换都会重新分配内存，并复制字节数组</p><p>转换为 []byte 类型</p><div class="language-go line-numbers-mode" data-ext="go"><pre class="language-go"><code><span class="token comment">// 字符串转换</span>
s1 <span class="token operator">:=</span> <span class="token string">&quot;big&quot;</span>
byteS1 <span class="token operator">:=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token function">byte</span><span class="token punctuation">(</span>s1<span class="token punctuation">)</span>
byteS1<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token char">&#39;p&#39;</span>
fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token function">string</span><span class="token punctuation">(</span>byteS1<span class="token punctuation">)</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>转换为rune类型</p><div class="language-go line-numbers-mode" data-ext="go"><pre class="language-go"><code><span class="token comment">// rune类型</span>
s2 <span class="token operator">:=</span> <span class="token string">&quot;你好golang&quot;</span>
byteS2 <span class="token operator">:=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token function">rune</span><span class="token punctuation">(</span>s2<span class="token punctuation">)</span>
byteS2<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token char">&#39;我&#39;</span>
fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token function">string</span><span class="token punctuation">(</span>byteS2<span class="token punctuation">)</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="格式化输出" tabindex="-1"><a class="header-anchor" href="#格式化输出" aria-hidden="true">#</a> 格式化输出</h3><p>在 Go 中，可以使用 <code>fmt</code>​ 包提供的函数进行格式化输出。常用的格式化输出函数包括：</p><ul><li>​<code>fmt.Printf()</code>​：按照指定的格式将数据输出到标准输出设备。</li><li>​<code>fmt.Println()</code>​：将参数格式化成字符串后，按照默认格式输出到标准输出设备。</li><li>​<code>fmt.Sprintf()</code>​：按照指定的格式将数据格式化为字符串。</li><li>​<code>fmt.Errorf()</code>​：将错误信息格式化为字符串。</li></ul><p>格式化输出的格式由一个字符串控制，其中包含普通文本和转换说明符。转换说明符以百分号 <code>%</code>​ 开头，其后紧跟一个字符，用于表示要输出的数据类型和格式。常用的转换说明符包括：</p><ul><li>​<code>%v</code>​：表示任意类型的值，按照默认格式输出。</li><li>​<code>%d</code>​：表示整数类型的值，按照十进制格式输出。</li><li>​<code>%f</code>​：表示浮点数类型的值，按照默认格式输出。</li><li>​<code>%s</code>​：表示字符串类型的值，按照默认格式输出。</li></ul><p>下面是一些具体的例子：</p><div class="language-go line-numbers-mode" data-ext="go"><pre class="language-go"><code><span class="token keyword">package</span> main

<span class="token keyword">import</span> <span class="token string">&quot;fmt&quot;</span>

<span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// 格式化输出整数和字符串</span>
    age <span class="token operator">:=</span> <span class="token number">20</span>
    name <span class="token operator">:=</span> <span class="token string">&quot;Alice&quot;</span>
    fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;My name is %s and I&#39;m %d years old.\\n&quot;</span><span class="token punctuation">,</span> name<span class="token punctuation">,</span> age<span class="token punctuation">)</span>

    <span class="token comment">// 格式化输出浮点数</span>
    pi <span class="token operator">:=</span> <span class="token number">3.1415926</span>
    fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;The value of pi is approximately %f.\\n&quot;</span><span class="token punctuation">,</span> pi<span class="token punctuation">)</span>
    fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;The value of pi is approximately %.2f.\\n&quot;</span><span class="token punctuation">,</span> pi<span class="token punctuation">)</span>

    <span class="token comment">// 格式化输出任意类型的值</span>
    a <span class="token operator">:=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token builtin">int</span><span class="token punctuation">{</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">}</span>
    fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;%v\\n&quot;</span><span class="token punctuation">,</span> a<span class="token punctuation">)</span>

    <span class="token comment">// 格式化输出到字符串</span>
    s <span class="token operator">:=</span> fmt<span class="token punctuation">.</span><span class="token function">Sprintf</span><span class="token punctuation">(</span><span class="token string">&quot;My name is %s and I&#39;m %d years old.&quot;</span><span class="token punctuation">,</span> name<span class="token punctuation">,</span> age<span class="token punctuation">)</span>
    fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>s<span class="token punctuation">)</span>
  
    <span class="token comment">// 可以一次输出多个参数，每个参数之间会自动添加一个空格，并在输出完成后自动换行。</span>
    fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;My name is&quot;</span><span class="token punctuation">,</span> name<span class="token punctuation">,</span> <span class="token string">&quot;and I&#39;m&quot;</span><span class="token punctuation">,</span> age<span class="token punctuation">,</span> <span class="token string">&quot;years old.&quot;</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>输出结果为：</p><div class="language-go line-numbers-mode" data-ext="go"><pre class="language-go"><code>My name is Alice and I&#39;m <span class="token number">20</span> years old<span class="token punctuation">.</span>
The value of pi is approximately <span class="token number">3.141593</span><span class="token punctuation">.</span>
The value of pi is approximately <span class="token number">3.14</span><span class="token punctuation">.</span>
<span class="token punctuation">[</span><span class="token number">1</span> <span class="token number">2</span> <span class="token number">3</span><span class="token punctuation">]</span>
My name is Alice and I&#39;m <span class="token number">20</span> years old<span class="token punctuation">.</span>
My name is Alice and I&#39;m <span class="token number">20</span> years old<span class="token punctuation">.</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="基本数据类型转换" tabindex="-1"><a class="header-anchor" href="#基本数据类型转换" aria-hidden="true">#</a> 基本数据类型转换</h2><h3 id="数字相互转换" tabindex="-1"><a class="header-anchor" href="#数字相互转换" aria-hidden="true">#</a> 数字相互转换</h3><div class="language-go line-numbers-mode" data-ext="go"><pre class="language-go"><code><span class="token comment">// 整型和浮点型之间转换</span>
<span class="token keyword">var</span> aa <span class="token builtin">int8</span> <span class="token operator">=</span> <span class="token number">20</span>
<span class="token keyword">var</span> bb <span class="token builtin">int16</span> <span class="token operator">=</span> <span class="token number">40</span>
fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token function">int16</span><span class="token punctuation">(</span>aa<span class="token punctuation">)</span> <span class="token operator">+</span> bb<span class="token punctuation">)</span>

<span class="token comment">// 建议整型转换成浮点型</span>
<span class="token keyword">var</span> cc <span class="token builtin">int8</span> <span class="token operator">=</span> <span class="token number">20</span>
<span class="token keyword">var</span> dd <span class="token builtin">float32</span> <span class="token operator">=</span> <span class="token number">40</span>
fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token function">float32</span><span class="token punctuation">(</span>cc<span class="token punctuation">)</span> <span class="token operator">+</span> dd<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p><strong>注意</strong>，高位转低位的时候，需要注意，会存在精度丢失，建议从低位转换成高位</p></blockquote><h3 id="数字转成字符串" tabindex="-1"><a class="header-anchor" href="#数字转成字符串" aria-hidden="true">#</a> 数字转成字符串</h3><p>第一种方式，就是通过 fmt.Sprintf()来转换</p><div class="language-go line-numbers-mode" data-ext="go"><pre class="language-go"><code><span class="token comment">// 字符串类型转换</span>
<span class="token keyword">var</span> i <span class="token builtin">int</span> <span class="token operator">=</span> <span class="token number">20</span>
<span class="token keyword">var</span> f <span class="token builtin">float64</span> <span class="token operator">=</span> <span class="token number">12.456</span>
<span class="token keyword">var</span> t <span class="token builtin">bool</span> <span class="token operator">=</span> <span class="token boolean">true</span>
<span class="token keyword">var</span> b <span class="token builtin">byte</span> <span class="token operator">=</span> <span class="token char">&#39;a&#39;</span>
str1 <span class="token operator">:=</span> fmt<span class="token punctuation">.</span><span class="token function">Sprintf</span><span class="token punctuation">(</span><span class="token string">&quot;%d&quot;</span><span class="token punctuation">,</span> i<span class="token punctuation">)</span>
fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;类型：%v-%T \\n&quot;</span><span class="token punctuation">,</span> str1<span class="token punctuation">,</span> str1<span class="token punctuation">)</span>

str2 <span class="token operator">:=</span> fmt<span class="token punctuation">.</span><span class="token function">Sprintf</span><span class="token punctuation">(</span><span class="token string">&quot;%f&quot;</span><span class="token punctuation">,</span> f<span class="token punctuation">)</span>
fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;类型：%v-%T \\n&quot;</span><span class="token punctuation">,</span> str2<span class="token punctuation">,</span> str2<span class="token punctuation">)</span>

str3 <span class="token operator">:=</span> fmt<span class="token punctuation">.</span><span class="token function">Sprintf</span><span class="token punctuation">(</span><span class="token string">&quot;%t&quot;</span><span class="token punctuation">,</span> t<span class="token punctuation">)</span>
fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;类型：%v-%T \\n&quot;</span><span class="token punctuation">,</span> str3<span class="token punctuation">,</span> str3<span class="token punctuation">)</span>

str4 <span class="token operator">:=</span> fmt<span class="token punctuation">.</span><span class="token function">Sprintf</span><span class="token punctuation">(</span><span class="token string">&quot;%c&quot;</span><span class="token punctuation">,</span> b<span class="token punctuation">)</span>
fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;类型：%v-%T \\n&quot;</span><span class="token punctuation">,</span> str4<span class="token punctuation">,</span> str4<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>第二种方法就是通过strconv包里面的集中转换方法进行转换</p><div class="language-go line-numbers-mode" data-ext="go"><pre class="language-go"><code><span class="token comment">// int类型转换str类型</span>
<span class="token keyword">var</span> num1 <span class="token builtin">int64</span> <span class="token operator">=</span> <span class="token number">20</span>
s1 <span class="token operator">:=</span> strconv<span class="token punctuation">.</span><span class="token function">FormatInt</span><span class="token punctuation">(</span>num1<span class="token punctuation">,</span> <span class="token number">10</span><span class="token punctuation">)</span>
fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;转换：%v - %T&quot;</span><span class="token punctuation">,</span> s1<span class="token punctuation">,</span> s1<span class="token punctuation">)</span>

<span class="token comment">// float类型转换成string类型</span>
<span class="token keyword">var</span> num2 <span class="token builtin">float64</span> <span class="token operator">=</span> <span class="token number">3.1415926</span>

<span class="token comment">/*
参数1：要转换的值
参数2：格式化类型 &#39;f&#39;表示float，&#39;b&#39;表示二进制，‘e’表示 十进制
参数3：表示保留的小数点，-1表示不对小数点格式化
参数4：格式化的类型，传入64位 或者 32位
	 */</span>
s2 <span class="token operator">:=</span> strconv<span class="token punctuation">.</span><span class="token function">FormatFloat</span><span class="token punctuation">(</span>num2<span class="token punctuation">,</span> <span class="token char">&#39;f&#39;</span><span class="token punctuation">,</span> <span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">64</span><span class="token punctuation">)</span>
fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;转换：%v-%T&quot;</span><span class="token punctuation">,</span> s2<span class="token punctuation">,</span> s2<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="字符串转成数字" tabindex="-1"><a class="header-anchor" href="#字符串转成数字" aria-hidden="true">#</a> 字符串转成数字</h3><div class="language-go line-numbers-mode" data-ext="go"><pre class="language-go"><code>str <span class="token operator">:=</span> <span class="token string">&quot;10&quot;</span>
<span class="token comment">// 第一个参数：需要转换的数，第二个参数：进制， 参数三：32位或64位</span>
num<span class="token punctuation">,</span><span class="token boolean">_</span> <span class="token operator">=</span> strconv<span class="token punctuation">.</span><span class="token function">ParseInt</span><span class="token punctuation">(</span>str<span class="token punctuation">,</span> <span class="token number">10</span><span class="token punctuation">,</span> <span class="token number">64</span><span class="token punctuation">)</span>

<span class="token comment">// 转换成float类型</span>
str2 <span class="token operator">:=</span> <span class="token string">&quot;3.141592654&quot;</span>
num<span class="token punctuation">,</span><span class="token boolean">_</span> <span class="token operator">=</span> strconv<span class="token punctuation">.</span><span class="token function">ParseFloat</span><span class="token punctuation">(</span>str2<span class="token punctuation">,</span> <span class="token number">10</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>‍</p>`,51);function m(v,b){const a=e("ExternalLinkIcon");return o(),p("div",null,[d,n("p",null,[n("a",r,[c("http://github.com/shopspring/decimal"),i(a)])]),k])}const h=t(u,[["render",m],["__file","数据类型.html.vue"]]);export{h as default};
